package main
import "fmt"
func main() { fmt.Println("Hello, Go!") }

var x int = 10
var s string = "go"
arr := [3]int{1,2,3}
sl := []int{1,2,3}
mp := map[string]int{"a":1}

type Item struct { Val int }
func mutateByValue(it Item) { it.Val = 10 }
func mutateByPtr(it *Item) { it.Val = 10 }
// Usage:
it := Item{Val:1}; mutateByValue(it); // it.Val == 1
mutateByPtr(&it); // it.Val == 10

// Slices share underlying array
a := []int{1,2,3}
b := a  // copies header, not the backing array
b[0] = 9 // now a[0] == 9

// Arrays are copied by value
a := [3]int{1,2,3}
b := a
b[0] = 9 // a[0] == 1, b[0] == 9

// Nil check
var p *Item
if p != nil { fmt.Println(p.Val) } // avoid panic

// Avoid unintended copies for large structs
func process(s BigStruct) { /* copies whole struct */ }
// prefer: func process(s *BigStruct)

type User struct { Name string }
func (u User) Short() string { return u.Name } // value receiver
func (u *User) SetName(n string) { u.Name = n } // pointer receiver

type Logger struct { Out io.Writer }
func NewLogger(w io.Writer) *Logger { return &Logger{Out: w} }
// Use embedding to add logging to a struct:
type Service struct { *Logger }

